const CreativeCore={

createProject:function(name,idea,type){

return {
 id:'PROJECT-'+Date.now(),
 name:name,
 idea:idea,
 type:type,
 created:new Date().toISOString(),
 characters:[],
 worlds:[],
 stories:[],
 assets:[]
};

},

saveProject:function(project){

let projects=JSON.parse(localStorage.getItem('bude_projects')||'[]');

projects.push(project);

localStorage.setItem('bude_projects',JSON.stringify(projects));

},

getProjects:function(){

return JSON.parse(localStorage.getItem('bude_projects')||'[]');

}

};

window.CreativeCore=CreativeCore;

document.getElementById('app').innerHTML=`
<div class='container'>
<h1>🤖 BudE</h1>
<h2>Creative Studio v3.0.2</h2>

<div class='card'>
Create your first project
</div>

<input id='projectName' placeholder='Project Name'>

<textarea id='idea' placeholder='Describe your idea'></textarea>

<select id='type'>
<option>Story</option>
<option>Character</option>
<option>World</option>
</select>

<button onclick='createProject()'>Create Project</button>

<div class='card' id='output'></div>

</div>`;


function createProject(){

let project=CreativeCore.createProject(
 document.getElementById('projectName').value,
 document.getElementById('idea').value,
 document.getElementById('type').value
);

CreativeCore.saveProject(project);

output.innerHTML='<pre>'+JSON.stringify(project,null,2)+'</pre>';

}
